import { forwardRef } from "react";
import type { ReactNode, HTMLAttributes } from "react";
import CircleCheckIcon from "@fortawesome/fontawesome-pro/svgs/regular/circle-check.svg";
import CircleExclamationIcon from "@fortawesome/fontawesome-pro/svgs/regular/circle-exclamation.svg";
import * as styles from "./ValidationMessage.css";
import { clsx } from "clsx";
import { Icon } from "../Icon";
import { ValidationMessageVariant } from "./ValidationMessage.config";

interface BaseProps extends HTMLAttributes<HTMLParagraphElement> {
  /**
   * The error message content
   */
  children: ReactNode;

  /**
   * State of the validation message. Determines the icon and color of the message.
   */
  variant: ValidationMessageVariant;
}

interface InvalidVariantProps {
  variant: "invalid";
  errorMessagePrefix: string;
  successMessagePrefix?: never;
}

interface ValidVariantProps {
  variant: "valid";
  successMessagePrefix: string;
  errorMessagePrefix?: never;
}

export type ValidationMessageProps = BaseProps &
  (InvalidVariantProps | ValidVariantProps);

/**
 * Type for invalid validation message configuration in field wrappers.
 * Includes `children` for the message content.
 */
export type ValidationMessageInvalidProps = Pick<BaseProps, "children"> &
  InvalidVariantProps;

/**
 * Type for valid validation message configuration in field wrappers.
 * Includes `children` for the message content.
 */
export type ValidationMessageValidProps = Pick<BaseProps, "children"> &
  ValidVariantProps;

export const ValidationMessage = forwardRef<
  HTMLParagraphElement,
  ValidationMessageProps
>(
  (
    {
      children,
      className,
      variant,
      errorMessagePrefix,
      successMessagePrefix,
      ...domProps
    },
    ref
  ) => {
    const { icon: IconComponent, prefix } =
      variant === "invalid"
        ? { icon: CircleExclamationIcon, prefix: errorMessagePrefix }
        : { icon: CircleCheckIcon, prefix: successMessagePrefix };

    return (
      <p
        ref={ref}
        role="alert"
        className={clsx(styles.validationMessage, className)}
        {...domProps}
      >
        <Icon
          size={20}
          aria-label={prefix}
          className={styles.validationIconVariants[variant]}
        >
          <IconComponent />
        </Icon>
        <span
          className={clsx(
            styles.validationText,
            styles.validationTextVariants[variant]
          )}
        >
          {children}
        </span>
      </p>
    );
  }
);

ValidationMessage.displayName = "ValidationMessage";
